// @ts-nocheck
import Link from "next/link";
import nextDynamic from "next/dynamic";
import { Section, Eyebrow } from "@/components/ui/Section";
import { StatusButtons } from "@/components/dashboard/StatusButtons";
import { readSessionFromCookies } from "@/lib/auth";
import { redirect } from "next/navigation";
import { getDb } from "@/lib/db";
import { site } from "@/lib/site";
import { cn } from "@/lib/cn";

export const dynamic = "force-dynamic";
export const runtime = "nodejs";

type LeadRow = {
  id: string;
  name: string;
  email: string;
  company: string | null;
  website: string | null;
  budget: string | null;
  message: string;
  source: string;
  status: string;
  score: number | null;
  service: string | null;
  intent: string | null;
  created_at: number;
  updated_at: number;
};

type Stats = {
  total: number;
  today: number;
  thisWeek: number;
  byStatus: Record<string, number>;
  byBudget: Record<string, number>;
};

function formatDate(ts: number): string {
  try {
    return new Date(ts).toLocaleString("en-US", {
      month: "short",
      day: "numeric",
      hour: "2-digit",
      minute: "2-digit",
      timeZoneName: "short",
    });
  } catch {
    return String(ts);
  }
}

function relativeTime(ts: number): string {
  const diff = Date.now() - ts;
  const min = Math.floor(diff / 60000);
  if (min < 1) return "just now";
  if (min < 60) return `${min}m ago`;
  const hr = Math.floor(min / 60);
  if (hr < 24) return `${hr}h ago`;
  const days = Math.floor(hr / 24);
  if (days < 7) return `${days}d ago`;
  return formatDate(ts);
}

const BUDGET_LABELS: Record<string, string> = {
  "<10k": "Under $10K",
  "10-25k": "$10–25K",
  "25-50k": "$25–50K",
  "50-100k": "$50–100K",
  "100k+": "$100K+",
  "not-sure": "Not sure",
};

export default async function DashboardPage({
  searchParams,
}: {
  searchParams?: { tab?: string | string[] };
}) {
  const { user } = await readSessionFromCookies();
  if (!user) {
    redirect("/login?next=/dashboard");
  }

  const tab = parseTab(searchParams?.tab);

  const db = getDb();
  const leads = db.prepare(
    `SELECT id, name, email, company, website, budget, message, source,
            service, intent, status, score, created_at, updated_at
       FROM leads ORDER BY created_at DESC LIMIT 200`,
  ).all() as LeadRow[];

  const now = Date.now();
  const dayMs = 24 * 60 * 60 * 1000;
  const weekMs = 7 * dayMs;

  const stats: Stats = {
    total: leads.length,
    today: 0,
    thisWeek: 0,
    byStatus: {},
    byBudget: {},
  };

  for (const l of leads) {
    if (now - l.created_at < dayMs) stats.today++;
    if (now - l.created_at < weekMs) stats.thisWeek++;
    stats.byStatus[l.status] = (stats.byStatus[l.status] || 0) + 1;
    if (l.budget) stats.byBudget[l.budget] = (stats.byBudget[l.budget] || 0) + 1;
  }

  const newLeads = leads.filter((l) => l.status === "new");
  const recent = leads.slice(0, 20);

  const replyRate = stats.total > 0 ? Math.round((stats.byStatus.replied / stats.total) * 100) : 0;

  return (
    <Section tone="paper" size="lg">
      <div className="flex items-start justify-between gap-4 flex-wrap mb-8">
        <div>
          <Eyebrow>BAZ · Internal</Eyebrow>
          <h1 className="font-display text-display-2xl font-medium tracking-[-0.04em] mt-2">
            Dashboard
          </h1>
          <p className="text-sm text-muted-foreground mt-2">
            Your cockpit. Leads, replies, and AI agent output will land here.
          </p>
        </div>
        <Link
          href="/admin"
          className="text-sm text-muted-foreground hover:text-foreground underline"
        >
          ← Admin home
        </Link>
      </div>

      {/* Stat strip */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-10">
        <Stat
          label="Leads total"
          value={stats.total}
