        <Stat
          label="Reply rate"
          value={`${replyRate}%`}
          hint={`${stats.byStatus.replied || 0} replied · ${stats.byStatus.archived || 0} archived`}
          tone={replyRate >= 50 ? "ok" : "neutral"}
